import { useEffect, useState } from "react"

const Usefetch=()=>{
    const [Data,setData] =useState(null)
    useEffect(()=>{
        console.log("STARTED")
        fetch("http://localhost:8000/TaskUploads")
        .then(res =>{
            console.log('Fetchin..')
            return res.json();
        })
        .then(data=>{
            setData(data)
            console.log(data)
        })
    },[])
    return{Data}
}

export default  Usefetch;
